@WebService
public class EnterpriseDataIntegrationService {
    
    private DocumentBuilderFactory documentBuilderFactory;
    
    public EnterpriseDataIntegrationService() {
        documentBuilderFactory = DocumentBuilderFactory.newInstance();
        documentBuilderFactory.setNamespaceAware(true);
        documentBuilderFactory.setIgnoringElementContentWhitespace(true);
        documentBuilderFactory.setCoalescing(true);
        documentBuilderFactory.setExpandEntityReferences(true);
    }
    
    @WebMethod
    public String processXMLData(String soapMessage) throws Exception {
        try {
            Document document = parseSOAPMessage(soapMessage);
            return processDocument(document);
        } catch (Exception e) {
            throw new Exception("Error processing XML data: " + e.getMessage(), e);
        }
    }
    
    private Document parseSOAPMessage(String soapMessage) throws Exception {
        try {
            DocumentBuilder documentBuilder = documentBuilderFactory.newDocumentBuilder();
            ByteArrayInputStream inputStream = new ByteArrayInputStream(soapMessage.getBytes("UTF-8"));
            return documentBuilder.parse(inputStream);
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new Exception("Failed to parse SOAP message", e);
        }
    }
    
    private String processDocument(Document document) throws Exception {
        Element rootElement = document.getDocumentElement();
        StringBuilder result = new StringBuilder();
        
        NodeList dataElements = rootElement.getElementsByTagName("Data");
        for (int i = 0; i < dataElements.getLength(); i++) {
            Element dataElement = (Element) dataElements.item(i);
            result.append(processDataElement(dataElement));
        }
        
        return result.toString();
    }
    
    private String processDataElement(Element dataElement) {
        StringBuilder elementResult = new StringBuilder();
        elementResult.append("Processing data element: ");
        
        NodeList childNodes = dataElement.getChildNodes();
        for (int i = 0; i < childNodes.getLength(); i++) {
            if (childNodes.item(i).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                Element childElement = (Element) childNodes.item(i);
                elementResult.append(processNestedElement(childElement));
            }
        }
        
        return elementResult.toString();
    }
    
    private String processNestedElement(Element element) {
        StringBuilder nestedResult = new StringBuilder();
        nestedResult.append("Element: ").append(element.getNodeName()).append(" = ");
        
        NodeList nestedNodes = element.getChildNodes();
        for (int i = 0; i < nestedNodes.getLength(); i++) {
            if (nestedNodes.item(i).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                Element nestedElement = (Element) nestedNodes.item(i);
                nestedResult.append(processComplexStructure(nestedElement));
            } else if (nestedNodes.item(i).getNodeType() == org.w3c.dom.Node.TEXT_NODE) {
                nestedResult.append(nestedNodes.item(i).getTextContent().trim());
            }
        }
        
        return nestedResult.toString();
    }
    
    private String processComplexStructure(Element element) {
        StringBuilder structureResult = new StringBuilder();
        
        if (element.hasChildNodes()) {
            NodeList children = element.getChildNodes();
            for (int i = 0; i < children.getLength(); i++) {
                if (children.item(i).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                    Element child = (Element) children.item(i);
                    structureResult.append(processComplexStructure(child));
                } else if (children.item(i).getNodeType() == org.w3c.dom.Node.TEXT_NODE) {
                    structureResult.append(children.item(i).getTextContent().trim());
                }
            }
        } else {
            structureResult.append(element.getTextContent().trim());
        }
        
        return structureResult.toString();
    }
    
    @WebMethod
    public String processLargeXMLPayload(String largeXMLData) throws Exception {
        try {
            Document document = parseLargeXML(largeXMLData);
            return processLargeDocument(document);
        } catch (Exception e) {
            throw new Exception("Error processing large XML payload: " + e.getMessage(), e);
        }
    }
    
    private Document parseLargeXML(String xmlData) throws Exception {
        try {
            DocumentBuilder documentBuilder = documentBuilderFactory.newDocumentBuilder();
            ByteArrayInputStream inputStream = new ByteArrayInputStream(xmlData.getBytes("UTF-8"));
            return documentBuilder.parse(inputStream);
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new Exception("Failed to parse large XML data", e);
        }
    }
    
    private String processLargeDocument(Document document) throws Exception {
        Element rootElement = document.getDocumentElement();
        StringBuilder result = new StringBuilder();
        
        processComplexDataStructure(rootElement, result, 0);
        
        return result.toString();
    }
    
    private void processComplexDataStructure(Element element, StringBuilder result, int depth) throws Exception {
        if (depth > 100) {
            throw new Exception("Maximum nesting depth exceeded");
        }
        
        String elementName = element.getNodeName();
        result.append("Element: ").append(elementName).append("\n");
        
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                Element childElement = (Element) children.item(i);
                processComplexDataStructure(childElement, result, depth + 1);
            } else if (children.item(i).getNodeType() == org.w3c.dom.Node.TEXT_NODE) {
                String textContent = children.item(i).getTextContent().trim();
                if (!textContent.isEmpty()) {
                    result.append("  Text: ").append(textContent).append("\n");
                }
            }
        }
    }
    
    @WebMethod
    public String importDataFromXML(String xmlData) throws Exception {
        try {
            Document document = parseSOAPMessage(xmlData);
            return executeDataImport(document);
        } catch (Exception e) {
            throw new Exception("Data import failed: " + e.getMessage(), e);
        }
    }
    
    private String executeDataImport(Document document) throws Exception {
        Element rootElement = document.getDocumentElement();
        List<String> importResults = new ArrayList<>();
        
        NodeList importElements = rootElement.getElementsByTagName("Import");
        for (int i = 0; i < importElements.getLength(); i++) {
            Element importElement = (Element) importElements.item(i);
            String result = processImportElement(importElement);
            importResults.add(result);
        }
        
        StringBuilder finalResult = new StringBuilder();
        for (String result : importResults) {
            finalResult.append(result).append("\n");
        }
        
        return finalResult.toString();
    }
    
    private String processImportElement(Element importElement) {
        StringBuilder result = new StringBuilder();
        result.append("Importing: ");
        
        NodeList fields = importElement.getElementsByTagName("Field");
        for (int i = 0; i < fields.getLength(); i++) {
            Element field = (Element) fields.item(i);
            String fieldName = field.getAttribute("name");
            String fieldValue = field.getTextContent();
            result.append(fieldName).append("=").append(fieldValue).append(" ");
        }
        
        return result.toString();
    }
}